import collections

def maxDepth(root):
    if not root:
        return 0
    queue = collections.deque([root])
    depth = 0
    while queue:
        for i in range(len(queue)):
            node = queue.popleft()
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        depth += 1
    return depth

